const body = $input.first().json.body || $input.first().json;
const profile = (body.profile || '').replace(/^@/, '').trim();
const posts = parseInt(body.posts) || 100;
const apifyKey = body.apifyKey || '';
const geminiKey = body.geminiKey || '';
const sheetId = body.sheetId || '';

if (!profile) throw new Error('profile is required');
if (!apifyKey) throw new Error('apifyKey is required');
if (!geminiKey) throw new Error('geminiKey is required');
if (!sheetId) throw new Error('sheetId is required - configure no painel admin');

return [{ json: { profile, posts, apifyKey, geminiKey, sheetId } }];

// Verifica se Apify retornou erro de crédito
const response = $input.first();
const statusCode = response.json.statusCode;

if (statusCode === 402) {
  throw new Error('APIFY_CREDIT_EXHAUSTED');
}

const posts = Array.isArray(response.json.body) ? response.json.body : response.json;
if (!Array.isArray(posts) || posts.length === 0) {
  throw new Error('Nenhum post coletado. Verifique o perfil.');
}

// Recupera as variáveis do nó anterior via $('Validar Input')
const vars = $('Validar Input').first().json;

// Mapeia tipo de post
function fmt(type) {
  if (type === 'Video') return 'Reels';
  if (type === 'Image') return 'Foto';
  if (type === 'Sidecar') return 'Carrossel';
  return type || 'Foto';
}

// Formata data
function fmtDate(ts) {
  if (!ts) return '';
  return new Date(ts).toLocaleDateString('pt-BR');
}

// Sanitiza legenda (remove quebras, trunca 200 chars)
function fmtLegenda(cap) {
  if (!cap) return '';
  return cap.replace(/[\r\n]+/g, ' ').trim().substring(0, 200) + (cap.length > 200 ? '...' : '');
}

const rows = posts.map(p => ({
  perfil: p.ownerUsername || vars.profile,
  link: p.url || '',
  formato: fmt(p.type),
  data: fmtDate(p.timestamp),
  curtidas: p.likesCount !== null && p.likesCount !== undefined ? String(p.likesCount) : 'Oculto',
  comentarios: String(p.commentsCount || 0),
  legenda: fmtLegenda(p.caption)
}));

return [{ json: { rows, geminiKey: vars.geminiKey, profile: vars.profile, postsCount: rows.length } }];

// Prepara prompt para Gemini classificar todos os posts de uma vez
const { rows, geminiKey, profile, postsCount } = $input.first().json;

const legends = rows.map((r, i) => `[${i+1}] Perfil: ${r.perfil} | Formato: ${r.formato} | Legenda: "${r.legenda || '(sem legenda)'}"`);

const prompt = `Você é especialista em análise de conteúdo de escolas católicas brasileiras no Instagram.

Analise os ${rows.length} posts abaixo e classifique cada um com:
- tema: categoria principal (seja específico, ex: "Coroação de Nossa Senhora / Espiritualidade", "Dia das Mães / Homenagem das turmas", "Atividade pedagógica / Disciplina escolar", "Natal / Espiritualidade", "Formação docente / Educação Católica", etc.)
- tom: como o conteúdo se comunica (ex: "Devocional e celebratório", "Afetivo e emotivo", "Institucional e informativo", "Educativo e lúdico", etc.)

Retorne SOMENTE um array JSON válido com ${rows.length} objetos {"tema":"...","tom":"..."}, na mesma ordem dos posts. Sem texto adicional.

Posts:
${legends.join('\n')}`;

return [{ json: { prompt, rows, geminiKey, profile, postsCount } }];

// Parseia resposta do Gemini e mescla com os posts
const geminiResponse = $input.first().json;
const { rows, profile, postsCount } = $('Preparar Prompt Gemini').first().json;

let classifications = [];
try {
  const text = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
  classifications = JSON.parse(text);
} catch(e) {
  // Fallback: classifica tudo como genérico se Gemini falhar
  classifications = rows.map(() => ({ tema: 'Atividade escolar / Vida escolar', tom: 'Informativo e institucional' }));
}

// Garante que temos classificação para todos os posts
const finalRows = rows.map((r, i) => ({
  Perfil: r.perfil,
  Link: r.link,
  Formato: r.formato,
  Data: r.data,
  Curtidas: r.curtidas,
  Comentarios: r.comentarios,
  Legenda: r.legenda,
  Tema: classifications[i]?.tema || 'Sem classificação',
  Tom_de_Voz: classifications[i]?.tom || '—'
}));

return finalRows.map(row => ({ json: row }));

const sheetId = $('Validar Input').first().json.sheetId;
const postsCount = $input.all().length;
return [{ json: {
  sheetUrl: `https://docs.google.com/spreadsheets/d/${sheetId}/edit`,
  postsCount,
  status: 'success'
}}];
